import React, { useEffect, useRef, useState } from 'react';
import { NavLink, useLocation } from 'react-router-dom';
import './NavBar.css';

const IconScan = () => (
  <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <path d="M3 7V5a2 2 0 0 1 2-2h2" /><path d="M17 3h2a2 2 0 0 1 2 2v2" />
    <path d="M21 17v2a2 2 0 0 1-2 2h-2" /><path d="M7 21H5a2 2 0 0 1-2-2v-2" />
    <circle cx="12" cy="12" r="3" /><path d="M12 9v-1" /><path d="M12 16v-1" />
    <path d="M9 12H8" /><path d="M16 12h-1" />
  </svg>
);

const IconDash = () => (
  <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <rect x="3" y="3" width="7" height="9" rx="1.5" /><rect x="14" y="3" width="7" height="5" rx="1.5" />
    <rect x="14" y="12" width="7" height="9" rx="1.5" /><rect x="3" y="16" width="7" height="5" rx="1.5" />
  </svg>
);

export default function NavBar() {
  const location = useLocation();
  const pillRef = useRef(null);
  const [scrolled, setScrolled] = useState(false);
  const [lastY, setLastY] = useState(0);

  // Shrink pill on scroll-down, expand on scroll-up
  useEffect(() => {
    const el = document.querySelector('.page-content') || window;
    const onScroll = () => {
      const y = el.scrollTop ?? window.scrollY;
      setScrolled(y > lastY && y > 60);
      setLastY(y);
    };
    el.addEventListener('scroll', onScroll, { passive: true });
    return () => el.removeEventListener('scroll', onScroll);
  }, [lastY]);

  return (
    <nav className={`navbar${scrolled ? ' navbar-compact' : ''}`} ref={pillRef}>
      {/* Active indicator pill that slides */}
      <div className="nav-indicator" style={{
        transform: `translateX(${location.pathname === '/' ? '0%' : '100%'})`
      }} />

      <NavLink to="/" end className={({ isActive }) => 'nav-item' + (isActive ? ' active' : '')}>
        <div className="nav-icon-wrap">
          <div className="nav-glow" />
          <IconScan />
        </div>
        <span className="nav-label">Scan</span>
      </NavLink>

      <NavLink to="/dashboard" className={({ isActive }) => 'nav-item' + (isActive ? ' active' : '')}>
        <div className="nav-icon-wrap">
          <div className="nav-glow" />
          <IconDash />
        </div>
        <span className="nav-label">Analytics</span>
      </NavLink>
    </nav>
  );
}
